import "join"
solunar = from(bucket:"signalk") |> range(start:now(), stop:24h) |> filter(fn:(r) => r._measurement == "solunar.forecast") |> filter(fn:(r) => r._field == "score" or r._field == "nearSun") |> keep(columns:["_time","_field","_value"]) |> pivot(rowKey:["_time"],columnKey:["_field"],valueColumn:"_value")
weather = from(bucket:"signalk") |> range(start:now(), stop:24h) |> filter(fn:(r) => r._measurement == "weather.forecast") |> filter(fn:(r) => r._field == "windSpeed" or r._field == "cloudCover") |> keep(columns:["_time","_field","_value"]) |> pivot(rowKey:["_time"],columnKey:["_field"],valueColumn:"_value")
join.inner(left:solunar, right:weather, on:(l,r) => l._time == r._time, as:(l,r) => {
  ws = r.windSpeed
  wf = if ws < 1.0 then 0.3 else if ws < 2.0 then 0.6 else if ws <= 5.0 then 1.0 else if ws <= 8.0 then 0.7 else if ws <= 12.0 then 0.3 else 0.0
  cf = 0.3 + 0.7 * r.cloudCover
  return {_time:l._time, _value:0.40*(l.score/4.0) + 0.30*float(v:l.nearSun) + 0.20*wf + 0.10*cf}
})

